#include<bits/stdc++.h>
using namespace std;
const int N=5005;
int n,a[N],ans[N],dp[N][N];
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        dp[i][i]=0;
    }
    for(int len=2;len<=n;len++)
    {
        int minn=-1;
        for(int l=1;l+len-1<=n;l++)
        {
            int r=l+len-1;
            dp[l][r]=dp[l+1][r-1]+abs(a[r]-a[l]);
            if(minn==-1) minn=dp[l][r];
            else minn=min(minn,dp[l][r]);
        }
        ans[len]=minn;
    }
    for(int i=1;i<=n;i++) cout<<ans[i]<<' ';
    return 0;
}
